import React from 'react';
import './Home.css';

// Importing images
import eventImage from '../pics/event.jpg';
import x from '../pics/back.jpg'

const Home = ({event}) => {
  return (
    <div className="home-main">
      <div style={{ position: 'relative', textAlign: 'center' }}>
        <img 
          src={eventImage} 
          style={{
            width: '100%', 
            height: '100vh', 
            objectFit: 'cover', 
            display: 'block', 
            margin: '0'
          }} 
        />
        
        <div style={{
          position: 'absolute', 
          top: '50%', 
          left: '50%', 
          transform: 'translate(-50%, -50%)', 
          color: 'rgb(255, 255, 255)', 
          padding: '20px', 
          borderRadius: '10px', 
          width: '50%', 
          background: 'linear-gradient(rgba(0, 0, 0, 0.5), rgba(0, 0, 0, 0.3))'
        }}>
          <h1 style={{ fontSize: '36px' }}>
            Welcome to Our Event Management System
          </h1>
          <p style={{ fontSize: '30px', margin: '10px 0' }}>
            Seamlessly organize and participate in events with ease!
          </p>
          <p style={{ fontSize: '30px', margin: '10px 0' }}>
            Whether you’re planning an event or looking to join one, our system is your go-to solution. Start exploring today!
          </p>
        </div>
      </div>

      <div className="event">
        {event.map((x)=>{
          return <div className="resize">
            <img src={x.img} alt="Wedding Event" />
            <div className="text">
              <h4>{x.title}</h4>
              <p>{x.about}</p>
              <a href="/event">JOIN</a>
            </div>
          </div>
        })}
        

        
      </div>
    </div>
  );
};

export default Home;
